const iconGrid = document.getElementById('iconGrid');
const searchInput = document.getElementById('searchInput');
const emptyState = document.getElementById('emptyState');
const emptyMessage = document.getElementById('emptyMessage');
const toast = document.getElementById('toast');

function renderIcons(iconsToRender) {
    iconGrid.innerHTML = ''; 

    if (iconsToRender.length === 0) {
        iconGrid.classList.add('hidden');
        emptyState.classList.remove('hidden');
        emptyMessage.innerText = `ไม่พบไอคอนที่ตรงกับ "${searchInput.value}"`;
        return;
    }

    iconGrid.classList.remove('hidden');
    emptyState.classList.add('hidden');

    iconsToRender.forEach((icon) => {
        
        const displaySvg = icon.svg.replace(
            'width="24" height="24"', 
            'class="w-8 h-8 md:w-10 md:h-10 text-neutral-600 group-hover:text-neutral-950 transition-colors duration-200"'
        );

        const button = document.createElement('button');
        button.className = "group relative flex flex-col items-center justify-center p-6 md:p-8 bg-white border border-neutral-200 rounded-2xl hover:border-neutral-300 hover:shadow-sm transition-all duration-200 ease-out hover:-translate-y-1 focus:outline-none focus:ring-2 focus:ring-neutral-950";
        
        const safeSvgStr = encodeURIComponent(icon.svg);

        button.innerHTML = `
            <div class="mb-4">${displaySvg}</div>
            <span class="text-sm font-medium text-neutral-500 group-hover:text-neutral-900 transition-colors">${icon.name}</span>
            
            <div class="absolute inset-0 bg-white/90 rounded-2xl opacity-0 group-hover:opacity-100 flex flex-col items-center justify-center transition-opacity duration-200 backdrop-blur-sm state-default">
                <span class="flex flex-col items-center text-neutral-900 font-medium">
                    <i data-lucide="copy" class="w-6 h-6 mb-2 text-neutral-700"></i>
                    <span class="text-sm">Copy SVG</span>
                </span>
            </div>
            
            <div class="absolute inset-0 bg-white/90 rounded-2xl opacity-0 flex flex-col items-center justify-center transition-opacity duration-200 backdrop-blur-sm state-copied hidden">
                <span class="flex flex-col items-center text-green-600 font-medium">
                    <i data-lucide="check" class="w-6 h-6 mb-2"></i>
                    <span class="text-sm">Copied!</span>
                </span>
            </div>
        `;

        button.onclick = () => handleCopy(decodeURIComponent(safeSvgStr), button);
        iconGrid.appendChild(button);
    });

    lucide.createIcons();
}

searchInput.addEventListener('input', (e) => {
    const query = e.target.value.toLowerCase();
    const filteredIcons = iconData.filter(icon => {
        return icon.name.toLowerCase().includes(query) || 
               icon.tags.some(tag => tag.toLowerCase().includes(query));
    });
    renderIcons(filteredIcons);
});

function clearSearch() {
    searchInput.value = '';
    renderIcons(iconData);
}

function handleCopy(text, buttonElement) {
    const textArea = document.createElement("textarea");
    textArea.value = text;
    document.body.appendChild(textArea);
    textArea.select();
    
    try {
        document.execCommand('copy');
        
        const defaultState = buttonElement.querySelector('.state-default');
        const copiedState = buttonElement.querySelector('.state-copied');
        
        defaultState.classList.add('hidden');
        copiedState.classList.remove('hidden');
        copiedState.classList.replace('opacity-0', 'opacity-100');

        toast.classList.replace('opacity-0', 'opacity-100');
        toast.classList.replace('translate-y-8', 'translate-y-0');

        setTimeout(() => {
            defaultState.classList.remove('hidden');
            copiedState.classList.add('hidden');
            copiedState.classList.replace('opacity-100', 'opacity-0');
            
            toast.classList.replace('opacity-100', 'opacity-0');
            toast.classList.replace('translate-y-0', 'translate-y-8');
        }, 2000);

    } catch (err) {
        console.error('Failed to copy', err);
    }
    document.body.removeChild(textArea);
}

renderIcons(iconData);
lucide.createIcons();